// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Order;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost.BagEstimate;
import org.eclipse.rdf4j.sail.lmdb.estimation.QuadSnapshotIdentity;
import org.junit.jupiter.api.Test;

class LmdbAccessCostModelTest {

	@Test
	void accessCostNeverChangesSemanticRows() {
		StatementPattern pattern = new StatementPattern(new Var("s"),
				new Var("p", SimpleValueFactory.getInstance().createIRI("urn:p")), new Var("o"));
		EstimateContext context = EstimateContext.root(pattern, new QuadSnapshotIdentity(1L, 2L, 3L), 4L)
				.withInvocationCount(5.0d)
				.withBoundNames(List.of("s"));
		BagEstimate semantic = BagEstimate.exact(20.0d, "semantic");

		LmdbAccessEstimate cost = new LmdbAccessCostModel().estimate(pattern, context, semantic);

		assertEquals(20.0d, cost.semanticRows());
		assertEquals(4.0d, cost.rowsPerInvocation());
		assertEquals(5.0d, cost.invocations());
		assertTrue(cost.totalWorkRows() >= 20.0d);
		assertTrue(cost.seeks() >= 1.0d);
	}

	@Test
	void blockingOperatorUsesMemoryWithoutRebasingRows() {
		StatementPattern pattern = new StatementPattern(new Var("s"), new Var("p"), new Var("o"));
		Order order = new Order(pattern);
		EstimateContext context = EstimateContext.root(order, new QuadSnapshotIdentity(1L, 2L, 3L), 4L);

		LmdbAccessEstimate cost = new LmdbAccessCostModel().estimate(order, context,
				BagEstimate.exact(100.0d, "semantic"));

		assertEquals(100.0d, cost.semanticRows());
		assertEquals(100.0d, cost.memoryRows());
		assertTrue(cost.totalWorkRows() > 100.0d);
	}
}
